#include <stdio.h>
int main() {
    int N, Q, L[100005], R[100005], x, y, sum = 0;
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &L[i], &R[i]);
        for (int j = L[i] - 1; j < R[i]; j++) {
            sum++;
        }
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        scanf("%d %d", &x, &y);
        int removed = 0;
        for (int j = 0; j < N; j++) {
            if (j == x - 1) continue;
            if (L[j] <= y && y <= R[j]) removed++;
        }
        if (removed % 2 == 1) sum ^= 1;
        if (sum % 2 == 0) printf("E\n");
        else printf("O\n");
    }
    return 0;
}

