const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const N = parseInt(readline());
const L = new Array(100005).fill(0);
const R = new Array(100005).fill(0);
let sum = 0;
for (let i = 0; i < N; i++) {
    const [li, ri] = readline().split(' ').map(Number);
    L[i] = li;
    R[i] = ri;
    for (let j = li - 1; j < ri; j++) {
        sum++;
    }
}
const Q = parseInt(readline());
for (let i = 0; i < Q; i++) {
    const [x, y] = readline().split(' ').map(Number);
    let removed = 0;
    for (let j = 0; j < N; j++) {
        if (j === x - 1) continue;
        if (L[j] <= y && y <= R[j]) removed++;
    }
    if (removed % 2 === 1) sum ^= 1;
    if (sum % 2 === 0) console.log('E');
    else console.log('O');
}
